// Aggregate all park data from the loop
const allParks = [];

// Collect all items - handle both simplified OpenAI structure and enriched data
for (const item of $input.all()) {
  allParks.push(item.json);
}

// Function to normalize phone numbers to +1 (XXX) XXX-XXXX format
function normalizePhone(phone) {
  if (!phone || phone === 'Not Found' || phone === 'N/A') return 'Not Found';

  // Remove all non-digit characters
  const digits = phone.replace(/\D/g, '');

  // Handle different digit lengths
  if (digits.length === 10) {
    // Format: (XXX) XXX-XXXX
    return `+1 (${digits.slice(0, 3)}) ${digits.slice(3, 6)}-${digits.slice(6)}`;
  } else if (digits.length === 11 && digits[0] === '1') {
    // Format: +1 (XXX) XXX-XXXX
    return `+1 (${digits.slice(1, 4)}) ${digits.slice(4, 7)}-${digits.slice(7)}`;
  } else if (digits.length > 0) {
    // Return as is with +1 prefix if it has some digits
    return `+1 ${phone}`;
  }

  return 'Not Found';
}

// Function to fill null/undefined values with 'Not Found'
function fillNotFound(value) {
  if (value === null || value === undefined || value === '' || value === 'null' || value === 'N/A') {
    return 'Not Found';
  }
  return value;
}

// Merge and deduplicate parks by name + city combination
const parkMap = new Map();

for (const park of allParks) {
  // Handle both simplified structure (name, city, phone) and full structure
  const parkName = fillNotFound(park.park_name || park.name);
  const parkCity = fillNotFound(park.park_city || park.city);
  const key = `${parkName}_${parkCity}`.toLowerCase();

  if (!parkMap.has(key)) {
    // Initialize with base data
    parkMap.set(key, {
      park_name: parkName,
      owner_name: fillNotFound(park.owner_name),
      owner_phone: normalizePhone(park.owner_phone || park.phone),
      estimated_pads: fillNotFound(park.estimated_pads),
      park_city: parkCity,
      town_population: fillNotFound(park.town_population),
      nearest_major_city: fillNotFound(park.nearest_major_city),
      distance_km: fillNotFound(park.distance_km),
      city_population: fillNotFound(park.city_population)
    });
  } else {
    // Merge enrichment data with existing data
    const existing = parkMap.get(key);

    // Update fields if they have better data (not 'Not Found')
    if (park.owner_name && park.owner_name !== 'Not Found' && park.owner_name !== 'N/A') {
      existing.owner_name = fillNotFound(park.owner_name);
    }
    if (park.owner_phone || park.phone) {
      const newPhone = normalizePhone(park.owner_phone || park.phone);
      if (newPhone !== 'Not Found') {
        existing.owner_phone = newPhone;
      }
    }
    if (park.estimated_pads && park.estimated_pads !== 'Not Found' && park.estimated_pads !== 'N/A') {
      existing.estimated_pads = fillNotFound(park.estimated_pads);
    }
    if (park.town_population && park.town_population !== 'Not Found' && park.town_population !== 'N/A') {
      existing.town_population = fillNotFound(park.town_population);
    }
    if (park.nearest_major_city && park.nearest_major_city !== 'Not Found' && park.nearest_major_city !== 'N/A') {
      existing.nearest_major_city = fillNotFound(park.nearest_major_city);
    }
    if (park.distance_km && park.distance_km !== 'Not Found' && park.distance_km !== 'N/A') {
      existing.distance_km = fillNotFound(park.distance_km);
    }
    if (park.city_population && park.city_population !== 'Not Found' && park.city_population !== 'N/A') {
      existing.city_population = fillNotFound(park.city_population);
    }
  }
}

// Convert map to array
const uniqueParks = Array.from(parkMap.values());

// Return the cleaned, merged, and deduplicated data
return uniqueParks.map(park => ({ json: park }));
